#include <stdio.h>
#include <string.h>

const long long MOD = 1000000007LL;

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char S[200005]; scanf("%s", S);
        long long ans = 1;
        int steps = (N - 1) / 2;
        for (int i = 0; i < steps; ++i) {
            int a = S[2*i] - '0';
            int b = S[2*i + 1] - '0';
            int c = S[2*i + 2] - '0';
            int cnt = 0;
            // &
            if ((a & b) == c) ++cnt;
            // |
            if ((a | b) == c) ++cnt;
            // ^
            if ((a ^ b) == c) ++cnt;
            ans = (ans * cnt) % MOD;
            if (cnt == 0) break;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

